  import sailpoint.tools.Util;
  import sailpoint.object.Identity;
  import sailpoint.api.PasswordGenerator;
  import sailpoint.object.PasswordPolicy;
  import java.text.Format;
  import java.text.SimpleDateFormat;
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.ProvisioningPlan.AccountRequest;
  import sailpoint.object.ProvisioningPlan.AttributeRequest;
  import sailpoint.object.Custom;
  import java.util.Iterator;
  import java.util.ArrayList;
  import sailpoint.api.IdentityService;
  import java.util.List;
  import sailpoint.object.Link;
  import sailpoint.object.Application;
  import sailpoint.api.IdentityService;
  import sailpoint.object.Attributes;


  String logName = "Ascension-RuleLibrary-Rehire";

  String    CUSTOM_OBJECT_NAME_COMPANY_MINISTRY_AD_DOMAIN_MAPPING = "Ascension-Custom-Ministry-Domain-Mapping" ;
  String    CUSTOM_OBJECT_NAME_COMPANY_NETBIOSNAMES_MAPPING = "Ascension-Custom-NetBios-Name-Company-Mapping" ;
  String    CUSTOM_OBJECT_NAME_ASC_CONTRACTOR_CONFIGURATION = "Ascension-Custom-ContractorConfiguration" ;
  String    CUSTOM_OBJECT_NAME_REHIRE_CONFIGURATION = "Ascension-Custom-Rehire-Configuration";

  String    DOT = "\\." ;
  String    DELIMITER = "," ;

  String APP_NAME_DB_PEOPLESOFT = "DB-Peoplesoft-HCM-Primary" ;
  String APP_NAME_MD_STAFF_AMITA = "MDStaff - AMITA";

  List includeReenableApplicationsList = null ;

  Custom companyMinistryADDomainMappingCustomObj = null ;

  Custom companyNetBiosNamesMappingCustomObj = null ;

  /***************************************************************************************************
    * This method adds the given daysToAdd to the given Date 
    * Input: daysToAdd, inputDate
    * Output : outputDate
    ***************************************************************************************************/

  public String addDaysToInputDate(String inputDate, int daysToAdd){
    
    String methodName = "addDaysToInputDate() - " ;
    debug(logName, methodName + "Start...");

    String outputDate = null;

    Custom customObj = context.getObjectByName(Custom.class, CUSTOM_OBJECT_NAME_ASC_CONTRACTOR_CONFIGURATION);

    if(customObj!=null){

      String outputDateformat = customObj.get("DateFormat");

      SimpleDateFormat inputFormat = new SimpleDateFormat("MM/dd/yyyy HH:mm:ss a zzz");
      SimpleDateFormat outputFormat = new SimpleDateFormat(outputDateformat);
      Calendar calendar = Calendar.getInstance();

      try {
        // Parse the input date
        Date date = inputFormat.parse(inputDate);
        calendar.setTime(date);

        // Add 90 days
        calendar.add(Calendar.DAY_OF_MONTH, daysToAdd);

        // set the date in the output format
        outputDate = outputFormat.format(calendar.getTime());

      } catch (Exception e) {
        
        error(logName, "Error in method " + methodName + " " + e);
        
      }
    } else {

      error(logName, methodName + "Error fetching custom object - " + CUSTOM_OBJECT_NAME_ASC_CONTRACTOR_CONFIGURATION) ;

    }  

    debug(logName, methodName + "End.");

    return outputDate;
  }

  /***************************************************************************************************
    * This method calculates the accountExpires Date by adding 90 days to the Effective Date
    * Input: identity
    * Output : accountExpiresDate
    ***************************************************************************************************/

  public String calculateAccountExpiresDate(Identity identity, String accountExpiresDate){
    
    String methodName = "calculateAccountExpiresDate() - " ;
    debug(logName, methodName + "Start...");

    try{
      if(identity != null){

        String identityType = identity.getStringAttribute("type");

        if(Util.nullSafeCaseInsensitiveEq("contractor", identityType)){
          
          //if identity type is contractor, set accountExpires as effective date from PeopleSoft + 90 days
          String expDate = calculateContractorExpirationDate(identity);
          
          if(Util.isNotNullOrEmpty(expDate)){
            
            accountExpiresDate = getADFormatedDateString(expDate); 
            
          } else{
            
            error(logName, methodName + "Cannot calculate Contractor Expiration Date for identity: " + identity.getName());
            
          }
          
        } else if(Util.nullSafeCaseInsensitiveEq("employee", identityType) || Util.nullSafeCaseInsensitiveEq("physician", identityType)){
          
          //if identity type is employee/physician, set accountExpires as 0 (never)
          accountExpiresDate = "0";
          
        }
      }
    } catch(Exception e){
      
      error(logName, "Error in method " + methodName + " " + e);
      
    }

    debug(logName, methodName + "End.");

    return accountExpiresDate;
  }

  /***************************************************************************************************
    * This method calculates the contractor expiration date logic for the identity
    * Input: identity
    * Output : expDate
    ***************************************************************************************************/

  public String calculateContractorExpirationDate(Identity identity){

    String methodName = "calculateContractorExpirationDate() - " ;
    debug(logName, methodName + "Start...");

    String expDate = "";
    String minExpDate = "";


    if(identity != null){
      expDate = identity.getAttribute("ctrexpDt");

      //Calculate Effective Date + 90 days

      Custom custom = context.getObjectByName(Custom.class, CUSTOM_OBJECT_NAME_REHIRE_CONFIGURATION);
      if(custom != null){
        
        int daysToAdd = custom.getInt("ACCOUNT_EXPIRES_REHIRE_CWR_DEFAULT");
        String effectiveDate = getEffectiveDateFromPeopleSoft(identity);

        if(Util.isNotNullOrEmpty(effectiveDate)){
          
          minExpDate = addDaysToInputDate(effectiveDate, daysToAdd);
          
        } else{
          
          error(logName, methodName + "Cannot find Effective Date from peoplesoft for identity: " + identity.getName());
          
        }
        
      } else{
        
        error(logName, methodName + "Error fetching custom object - " + CUSTOM_OBJECT_NAME_REHIRE_CONFIGURATION);
        
      }

      if(Util.isNotNullOrEmpty(minExpDate)){
        
        if(Util.isNullOrEmpty(expDate)){
          
          //if Contractor Expiration Date is null assign Effective Date + 90 days as Contractor Expiry Date
          expDate = minExpDate;
          
        } else{ 
          try{
            
            Custom customObj = context.getObjectByName(Custom.class, CUSTOM_OBJECT_NAME_ASC_CONTRACTOR_CONFIGURATION);
            if(customObj!=null){
              
              String expDateFormat = customObj.get("DateFormat");
              SimpleDateFormat sdf = new SimpleDateFormat(expDateFormat);
              Date date1 = sdf.parse(expDate);
              Date date2 = sdf.parse(minExpDate);
              
              if(date1.before(date2)){
                
                //if current Contractor Expiration Date is less than Effective Date + 90 days, extend it to Effective Date + 90 days
                expDate = minExpDate;
                
              }
              
            } else {

              error(logName, methodName + "Error fetching custom object - " + CUSTOM_OBJECT_NAME_ASC_CONTRACTOR_CONFIGURATION) ;

            }  
          } catch(Exception e){
            
            error(logName, methodName + "Error occurred in parsing expDate or minExpDate for identity: " + identity.getName());
            
          }
        }
        
      } else{
        
        error(logName, methodName + "Cannot calculate Effective Date plus 90 days for identity: " + identity.getName());
        
      }
    }

    debug(logName, methodName + "End.");

    return expDate;
  }

  /***************************************************************************************************
    * This method updates/removes the contractor expiration date on the identity for non-persona users
    * Input: identity
    * Output : effectiveDate
    ***************************************************************************************************/

  public void updateContractorExpirationDate(String identityName){
    String methodName = "updateContractorExpirationDate() - " ;
    debug(logName, methodName + "Start...");

    boolean isInPersonaEnabledMinistry = isInMinistriesList(identityName);

    Identity identity = context.getObjectByName(Identity.class, identityName);

    if(identity != null){

      if(!isInPersonaEnabledMinistry){

        String identityType = identity.getStringAttribute("type");

        if(Util.nullSafeCaseInsensitiveEq("employee", identityType) || Util.nullSafeCaseInsensitiveEq("physician", identityType)){

          //remove Contractor Expiration Date if the identity is a Non-Persona Employee/Physician      
          identity.removeAttribute("ctrexpDt");

        } else if(Util.nullSafeCaseInsensitiveEq("contractor", identityType)){

          //set Contractor Expiration Date if identity is a Non-Persona Contractor 
          String expDate = calculateContractorExpirationDate(identity);

          if(Util.isNotNullOrEmpty(expDate)){
            identity.setAttribute("ctrexpDt", expDate);
          }

        }

        context.startTransaction();
        context.saveObject(identity);
        context.commitTransaction();

      }

    } else {

      error(logName, methodName + "Cannot find identity object for identity: " + identityName);

    }

    debug(logName, methodName + "End.");
  }

  /***************************************************************************************************
    * This method gets the EFFDT from db-peoplesoft
    * Input: identity
    * Output : effectiveDate
    ***************************************************************************************************/

  public String getEffectiveDateFromPeopleSoft(Identity identity){
    String methodName = "getEffectiveDateFromPeopleSoft() - " ;
    debug(logName, methodName + "Start...");
    String effDate = null;
    if(null != identity){
      Application application = context.getObjectByName(Application.class, "DB-Peoplesoft-HCM-Primary");
      IdentityService idSvc = new IdentityService(context);
      try{
        List pplSoftLink = idSvc.getLinks(identity, application);
        if(!Util.isEmpty(pplSoftLink) && pplSoftLink.get(0) != null){
          effDate = pplSoftLink.get(0).getAttribute("EFFDT");
        }
      } catch(Exception e){
        error(logName, "Error in method " + methodName + " " + e);
      }
    }
    debug(logName, methodName + "End.");
    return effDate;
  }

  /***************************************************************************************************
    * This method gets the EFFDT from db-peoplesoft
    * Input: identity
    * Output : effectiveDate
    ***************************************************************************************************/

  public String findEffectiveDate(Identity identity){
    String methodName = "findEffectiveDate() - " ;
    debug(logName, methodName + "Start...");
    String effectiveDate = null;
    if(null != identity){
      effectiveDate = getEffectiveDateFromPeopleSoft(identity);
      try{
        Date dateObject = new SimpleDateFormat("MM/dd/yyyy HH:mm:ss a zzz").parse(effectiveDate);
        effectiveDate = new SimpleDateFormat("MM/dd/yyyy").format(dateObject);
      } catch(Exception e){
        error(logName, "Error in method " + methodName + " " + e);
      }
    }

    debug(logName, methodName + "End.");
    return effectiveDate;
  }

  /***************************************************************************************************
    * This method is checks if the valid AD account exists for the identity
    * Input: identityName
    * Output : ifMatchingADAccountExists
    ***************************************************************************************************/

  public boolean checkIfValidADAccountExists(String identityName){
    String methodName = "getReasonForNonPersonaManualAction() - " ;
    debug(logName, methodName + "Start...");
    boolean ifMatchingADAccountExists = false; 

    String domainValue = "";

    identityObject = context.getObjectByName(Identity.class, identityName);

    if(!isPeopleSoftUser(identityName)){
      domainValue = identityObject.getAttribute("domain");
    }

    Map rehireAccountsMap = findPotentialAccountsForRehire(identityName, domainValue);

    if(rehireAccountsMap != null){
      potentialAccountsList = rehireAccountsMap.get("potentialAccountsList");
    }

    if(potentialAccountsList != null){
      for(String potentialAccount: potentialAccountsList){

        if(potentialAccount.startsWith("AD-")){

          ifMatchingADAccountExists = true ; 

        }
      }
    }
    debug(logName, methodName + "End.");
    return ifMatchingADAccountExists;
  }

  /***************************************************************************************************
    * This method is to get the reason for a Non Persona Manual Action Workitem
    * Input: idSamAccountName, ifMatchingADAccountExists
    * Output : reason
    ***************************************************************************************************/

  public String getReasonForNonPersonaManualAction(String idSamAccountName, boolean ifMatchingADAccountExists){
    String methodName = "getReasonForNonPersonaManualAction() - " ;
    debug(logName, methodName + "Start...");
    String reason = null;
    if(idSamAccountName == null && Util.isEmpty(idSamAccountName)){
      reason = "Network Logon ID is null";
    } else if(!ifMatchingADAccountExists){
      reason = "No valid AD account Found";
    }
    debug(logName, methodName + "End.");
    return reason;
  }

  /***************************************************************************************************
    * This method is to configure the Case Type for a Non Persona Manual Action Workitem
    * Input: reason, conversionType
    * Output : workitemName
    ***************************************************************************************************/

  public String setWorkItemNameForNonPersonaManualAction(String reason, String conversionType){
    String methodName = "setWorkItemNameForNonPersonaManualAction() - " ;
    debug(logName, methodName + "Start...");
    String workitemName = "Rehire - Non Persona Identity";
    if(null != reason){
      workitemName = workitemName + " - " + reason;
    }
    if(null != conversionType){
      if(Util.nullSafeCaseInsensitiveEq(conversionType, "empClassChange")){
        workitemName = workitemName + " - " + "Employee Class Change";
      } else if(Util.nullSafeCaseInsensitiveEq(conversionType, "typeChange")){
        workitemName = workitemName + " - " + "Employee Type Change";
      }
    }
    debug(logName, methodName + "End.");
    return workitemName;
  }

  /***************************************************************************************************
    * This method is to configure the Case Type for a Market Transfer Workitem
    * Input: oldSetIDLocation, newSetIDLocation, conversionType
    * Output : workitemName
    ***************************************************************************************************/

  public String setWorkItemNameForMarketTransfer(String oldSetIDLocation, String newSetIDLocation, String conversionType){
    String methodName = "setWorkItemNameForMarketTransfer() - " ;
    debug(logName, methodName + "Start...");
    String workitemName = "Rehire";
    if(!Util.nullSafeCaseInsensitiveEq(oldSetIDLocation, newSetIDLocation)){
      if(isPersonaSETID(oldSetIDLocation)){
        workitemName = workitemName + " - " + "Persona Change (Persona to Non-Persona)";
      } else if(isPersonaSETID(newSetIDLocation)){
        workitemName = workitemName + " - " + "Persona Change (Non-Persona to Persona)";
      } else{
        workitemName = workitemName + " - " + "Non-Persona Identity";
      }
      
      workitemName = workitemName + " - " + "Market Transfer";

      if(null != conversionType){
        if(Util.nullSafeCaseInsensitiveEq(conversionType, "empClassChange")){
          workitemName = workitemName + " - " + "Employee Class Change";
        } else if(Util.nullSafeCaseInsensitiveEq(conversionType, "typeChange")){
          workitemName = workitemName + " - " + "Employee Type Change";
        }
      }
    }
    debug(logName, methodName + "End.");
    return workitemName;
  }

  /***************************************************************************************************
    * This method is to determine whether the given SETID_LOCATION belongs to a persona enabled ministry
    * Input: setID
    * Output : isPersonaSETIDLocation
    ***************************************************************************************************/

  public boolean isPersonaSETID(String setID){
    String methodName = "getRehireTypeMessage() - " ;
    debug(logName, methodName + "Start...");
    boolean isPersonaSETIDLocation = false;
    Custom contractorCustom = context.getObject(Custom.class,"Ascension-Custom-ContractorConfiguration");
    List personasSETID = contractorCustom.get("Personas SETID_LOCATION");
    if(null != personasSETID && personasSETID.contains(setID)){
      isPersonaSETIDLocation = true;
    }
    debug(logName, methodName + "End.");
    return isPersonaSETIDLocation;
  }

  /***************************************************************************************************
    * This method is to find the rehire type detail
    * Input: rehireType, conversionType
    * Output : message
    ***************************************************************************************************/

  public String getRehireTypeMessage(String rehireType, String conversionType){
    String methodName = "getRehireTypeMessage() - " ;
    debug(logName, methodName + "Start...");
    String message = null;
    if(null != rehireType){
      if(rehireType.equals("Enable User")){
        message = "Normal Rehire";
      } else if(rehireType.equals("Type Transfer")){
        message = "Rehire with " + conversionType;
      } else if(rehireType.equals("Market Transfer")){
        message = "Market Transfer";
        if(null != conversionType){
          message = message + " with " + conversionType;
        }
      }
    }
    debug(logName, methodName + "End.");
    return message;
  }

  /***************************************************************************************************
    * This method returns AD account info of the given account name for the identity
    * Input: identityName, validAccountName
    * Output : accountInfo
    ***************************************************************************************************/

  public Map getADAccountInfo(String identityName, String validAccountName){
    String methodName = "getADAccountInfo() - " ;
    debug(logName, methodName + "Start...");
    Map accountInfo = new HashMap();
    if(identityName != null){
      Identity identity = context.getObjectByName(Identity.class, identityName);
      List linksAccount= (List) identity.getLinks();
      if( null != linksAccount){
        Iterator itrlinksAccount = linksAccount.iterator();
        while (itrlinksAccount.hasNext()){
          Link account = (Link) itrlinksAccount.next();
          String appName = account.getApplicationName();
          String accountName = account.getNativeIdentity();
          String appType = account.getApplication().getType();

          if(Util.isNotNullOrEmpty(appName) && Util.isNotNullOrEmpty(accountName) && Util.isNotNullOrEmpty(appType) && appType.equalsIgnoreCase("Active Directory - Direct")){
            if(Util.nullSafeCaseInsensitiveEq(accountName, validAccountName)){              
              accountInfo.put("isAccountEnabled", account.getIiqDisabled());
              accountInfo.put("distinguishedName", account.getAttribute("distinguishedName"));
              accountInfo.put("extAttribute6", account.getAttribute("extensionAttribute6"));
              accountInfo.put("msExchExtAttr40", account.getAttribute("msExchExtensionAttribute40"));
            }
          }
        }
      }
    }
    debug(logName, methodName + "End.");
    return accountInfo;
  }

  /***************************************************************************************************
    * This method returns true if the user is an MDStaff User
    * Input: identityName
    * Output : isMDStaffUser
    ***************************************************************************************************/

  public boolean isMDStaffUser(String identityName){
    String methodName = "isMDStaffUser() - " ;
    debug(logName, methodName + "Start...");
    boolean isMDStaffUser = false;
    if(identityName != null){
      Identity identity = context.getObjectByName(Identity.class, identityName);
      Application mdstaffApp = context.getObjectByName(Application.class,"MDStaff - AMITA");
      IdentityService idService = new IdentityService(context);
      if(identity != null){
        if(null != mdstaffApp && !Util.isEmpty(idService.getLinks( identity, mdstaffApp))){
          isMDStaffUser = true;
        }
      }
    }
    debug(logName, methodName + "End.");
    return isMDStaffUser;
  }

  /***************************************************************************************************
    * This method gets the display name of the links for the identity
    * Input: identityName
    * Output : displayNames
    ***************************************************************************************************/

  public Map getLinkDisplayNames(String identityName){
    String methodName = "getLinkDisplayNames() - " ;
    debug(logName, methodName + "Start...");

    Map displayNames = new HashMap();

    if(identityName != null){
      Identity identity = context.getObjectByName(Identity.class, identityName );

      List accountsAD = new ArrayList();
      List accountsServiceNow = new ArrayList();
      String accountGSuite = "";
      String accountDBPplSoft = "";

      if(identity != null){
        List linksAccount= (List) identity.getLinks(); 
        if( null != linksAccount){

          String accountName = "";
          String appName = "";
          String appType = "";

          Iterator itrlinksAccount = linksAccount.iterator();
          while (itrlinksAccount.hasNext()){

            Link account = (Link) itrlinksAccount.next();

            if(null != account  && null != account.getApplication()){
              appName = account.getApplicationName();                 
              accountName = account.getDisplayName();
              appType = account.getApplication().getType();

              if(Util.isNotNullOrEmpty(appName) && Util.isNotNullOrEmpty(accountName) && Util.isNotNullOrEmpty(appType)){
                if(appType.equalsIgnoreCase("Active Directory - Direct")){
                  accountsAD.add(accountName);
                } else if(appType.equalsIgnoreCase("ServiceNow")){
                  accountsServiceNow.add(accountName);
                } else if(appName.equalsIgnoreCase("DB-Peoplesoft-HCM-Primary")){
                  accountDBPplSoft = accountName;
                } else if(appName.equalsIgnoreCase("GSuite")){
                  accountGSuite = accountName;
                }
              } 
            }
          }
          if(accountsAD != null && !Util.isEmpty(accountsAD)){
            displayNames.put("AD accounts", accountsAD.toString());
          }
          if(accountsServiceNow != null && !Util.isEmpty(accountsServiceNow)){
            displayNames.put("ServiceNow accounts", accountsServiceNow.toString());
          }
          displayNames.put("PeopleSoft account", accountDBPplSoft);
          displayNames.put("GSuite account", accountGSuite);
        } 
      }
    }
    debug(logName, methodName + "End.");

    return displayNames;
  }


  /***************************************************************************************************
    * This method gets the SETID_LOCATION from db-peoplesoft
    * Input: identity
    * Output : setIDLocation
    ***************************************************************************************************/

  public String findSetIDLocation(Identity identity){
    String methodName = "findSetIDLocation() - " ;
    debug(logName, methodName + "Start...");
    String setIDLocation = null;
    if(null != identity){
      Application application = context.getObjectByName(Application.class, "DB-Peoplesoft-HCM-Primary");
      IdentityService idSvc = new IdentityService(context);
      try{
        List pplSoftLink = idSvc.getLinks(identity, application);
        if(!Util.isEmpty(pplSoftLink) && pplSoftLink.get(0) != null){
          setIDLocation = pplSoftLink.get(0).getAttribute("SETID_LOCATION");
        }
      } catch(Exception e){
        error(logName, "Error in method findSetIDLocation " + e);
      }
    }
    debug(logName, methodName + "End.");
    return setIDLocation;
  }

  /***************************************************************************************************
    * This method finds the samAccountName of the identity
    * Input: identityName
    * Output : idSamAccountName
    ***************************************************************************************************/

  public String findSamAccountNameForIdentity(String identityName){ 
    String methodName = "findSamAccountNameForIdentity() - " ;
    debug(logName, methodName + "Start...");

    String idSamAccountName = null;

    if(null != identityName){
      Identity identity = context.getObjectByName(Identity.class, identityName);
      idSamAccountName = identity.getStringAttribute("samAccountName");

      if(null == idSamAccountName){
        Application application = context.getObjectByName(Application.class, "DB-Peoplesoft-HCM-Primary");
        IdentityService idSvc = new IdentityService(context);
        try{
          List pplSoftLink = idSvc.getLinks(identity, application);
          if(!Util.isEmpty(pplSoftLink) && pplSoftLink.get(0) != null){
            idSamAccountName = pplSoftLink.get(0).getAttribute("OPRID");
          }
        } catch(Exception e){
          error(logName, "Error in method findSamAccountNameForIdentity " + e);
        }
      }
    } 
    debug(logName, "samAccountName: " + idSamAccountName);
    debug(logName, methodName + "End.");
    return idSamAccountName;
  }

  /***************************************************************************************************
    * This method updates the identity attributes for the rehire process
    * Input: identityName
    * Output : null
    ***************************************************************************************************/

  public void updateIdentityAttributesForRehire(String identityName){ 
    String methodName = "updateIdentityAttributesForRehire() - " ;
    debug(logName, methodName + "Start...");

    if(null != identityName){
      Identity identity = context.getObjectByName(Identity.class, identityName);
      if(null != identity){
        //set inactive to false
        identity.setAttribute("inactive", "false");

        //set maunalterm to NO 
        identity.setAttribute("manualTerm", "No");

        //set leaverdate to Null
        identity.setAttribute("leaverDate","");

        context.startTransaction();
        context.saveObject(identity);
        context.commitTransaction();
      }
    }
    debug(logName, methodName + "End.");
  }

  /***************************************************************************************************
    * This method finds the rehireType for the identity based on Type and Set_ID_Location
    * Method returns the rehireType
    * Input: previousIdentitySetIDLocation, newIdentitySetIDLocation, previousIdentityType, newIdentityType
    * Output : rehireType - String
    ***************************************************************************************************/

  public String findRehireTypeForIdentity(String oldSetIDLocation, String newSetIDLocation, String conversionType){
    String methodName = "findRehireTypeForIdentity() - " ;
    debug(logName, methodName + "Start...");
    String rehireType = "";
    if(!Util.nullSafeCaseInsensitiveEq(oldSetIDLocation, newSetIDLocation)){
      rehireType = "Market Transfer";
    } else if(null != conversionType){
      rehireType = "Type Transfer";
    } else {
      rehireType = "Enable User";
    }
    debug(logName, methodName + "End.");
    return rehireType;
  }

  /***************************************************************************************************
    * This method finds the conversion type for the identity based on Type and empClassChange
    * Method returns the conversionType
    * Input: oldType, newType, oldEmplClass, newEmplClass
    * Output : conversionType - String
    ***************************************************************************************************/

  public String findConversionTypeForIdentity(String oldType, String newType, String oldEmplClass, String newEmplClass){
    String methodName = "findConversionTypeForIdentity() - " ;
    debug(logName, methodName + "Start...");
    String conversionType = null;
    if(oldType != null &&  newType !=null && !(oldType.equalsIgnoreCase(newType)) && (newType.equalsIgnoreCase("employee"))  && (oldType.equalsIgnoreCase("contractor"))){
      conversionType = "typeChange";
    } else {
      List emplClassValues=new ArrayList();

      Custom gsuiteCustomObject = context.getObject(Custom.class,"Ascension-Custom-Gsuite");
      if(gsuiteCustomObject != null){
        Attributes attr = gsuiteCustomObject.getAttributes();
        if(attr != null){
          Map objectMap = attr.getMap();
          if(objectMap != null){
            emplClassValues = objectMap.get("emplClassForAutoProvisioning");
          }
        }
      }
      if(newType!=null && newType.equalsIgnoreCase("contractor")){
        debug(logName, "type is:::"+newType);
        debug(logName, "emplClass present the list ::"+emplClassValues.contains(newEmplClass));

        //If a contractor empl class value changes to c28 else if it changes from c28 to other empClass Change
        if(newEmplClass!=null  && emplClassValues.contains(newEmplClass) && (oldEmplClass==null || (oldEmplClass!=null && !emplClassValues.contains(oldEmplClass)))){
          conversionType = "empClassChange";
        } else if(oldEmplClass!=null  && emplClassValues.contains(oldEmplClass) && (newEmplClass==null || (newEmplClass!=null && !emplClassValues.contains(newEmplClass) ))){
          conversionType = "empClassChange";
        }
      }
    }
    debug(logName, "conversionType: " + conversionType);
    debug(logName, methodName + "End.");
    return conversionType;
  }

  /***************************************************************************************************
    * This method reset the password the application
    * Method returns the changed password
    * Input: applicationName, identity
    * Output : password - String
    ***************************************************************************************************/

  public String resetPassword(String applicationName, Identity identity){
    String methodName = "resetPassword() - " ;
    debug(logName, methodName + "Start...");
    PasswordPolicy policy = context.getObjectByName(PasswordPolicy.class, "AD Default Password Policy"); 
    String password = null;

    if(Util.isNotNullOrEmpty(applicationName) && (Util.nullSafeCaseInsensitiveEq(applicationName,"AD-AMITA") || Util.nullSafeCaseInsensitiveEq(applicationName,"AD-PRESENCEHEALTH"))){
      password = generatePasswordForAmitaAD(identity);
    }
    else if(policy!=null)
    {       
      password = new PasswordGenerator(context).generatePassword(policy);
    }
    debug(logName, methodName + "End.");
    return password;
  }

  /****************************************************************************************************************************
    * This method checks the leaver date within the limit from custom and is not one of the preset date from the Leaver +61 event
    * Method returns true if the difference is greater than the limit 
    * Input: identityName
    * Output : isDatePastLimit - boolean
    *****************************************************************************************************************************/

  public boolean checkIfLeaverDatePastLimit(String identityName){
    String methodName = "checkIfLeaverDatePastLimit() - " ;
    debug(logName, methodName + "Start...");

    boolean isDatePastLimit = true;
    long differenceInDays = Integer.MAX_VALUE;
    Custom custom = context.getObjectByName(Custom.class, CUSTOM_OBJECT_NAME_REHIRE_CONFIGURATION);
    Identity identity = context.getObjectByName(Identity.class, identityName);

    List datesFromLeaver61Event = custom.get("Leaver Dates Excluded From Leaver61 Event");

    int leaverDateLimitForPasswordReset = custom.getInt("RESET_PASSWORD_LEAVER_DATE_LIMIT");

    String date= identity.getAttribute("leaverDate");
    debug(logName, "leaverDate: " + date);
    if(Util.isNotNullOrEmpty(date)){
      differenceInDays = calculateDifferenceinDays(date);
      debug(logName, "differenceInDays from leaver date: " + differenceInDays);
      if(datesFromLeaver61Event.contains(date) || differenceInDays < leaverDateLimitForPasswordReset){
        isDatePastLimit = false;
      }
    }
    debug(logName, "isDatePastLimit: " + isDatePastLimit);
    debug(logName, methodName + "End.");
    return isDatePastLimit;
  }

  /***************************************************************************************************
    * This method calculates the difference between the given date and the current date
    * Method returns the difference in days
    * Input: date
    * Output : differenceInDays - String
    ***************************************************************************************************/

  public long calculateDifferenceinDays(String date){
    String methodName = "calculateDifferenceinDays() - " ;
    debug(logName, methodName + "Start...");
    SimpleDateFormat sdf = new SimpleDateFormat("yyyyMMdd");
    Date givenDate = sdf.parse(date);
    Date currentDate = new Date();

    // Calculate the difference in milliseconds between the two dates
    long differenceInMillis = currentDate.getTime() - givenDate.getTime();

    // Convert milliseconds to days (1 day = 24 * 60 * 60 * 1000 milliseconds)
    long differenceInDays = differenceInMillis / (1000 * 60 * 60 * 24);
    debug(logName, methodName + "End.");
    return differenceInDays;
  }

  /***************************************************************************************************
    * This method is to add enable account requests to the provisioning plan
    * Method returns the Account Requests and Pasword as a Map
    * Input: identityName, accountNameAD
    * Output : accReqs - Map
    ***************************************************************************************************/

  public Map enableAccount(String identityName, Map matchingAccountNames){
    String methodName = "enableAccount() - " ;
    debug(logName, methodName + "Start...");
    debug(logName, "matchingAccountNames: " + matchingAccountNames);

    List accReqs = new ArrayList();
    Map outputMap = new HashMap();
    Map displayNamesOfEnabledAccounts = new HashMap();
    List displayNamesofAD = new ArrayList();
    List displayNamesofSNow = new ArrayList();

    String appName = null;
    String accountName = null;
    String appType = null;
    String locationID = null;
    String domainAD = null;
    String domainValue = null;
    String password = null;
    String valueCN = null ;
    String adExpDate = null;
    String description = "";
    String activeOU = null;
    HashMap activeOUMap = new HashMap();
    Map domainMap = new HashMap();

    List listOfAccounts = new ArrayList();

    List matchingADAccounts = new ArrayList();
    List matchingServiceNowAccounts = new ArrayList();

    if(null != identityName){

      if(null != matchingAccountNames){
        matchingADAccounts = matchingAccountNames.get("AD accounts");
        matchingServiceNowAccounts = matchingAccountNames.get("ServiceNow accounts");
      }

      Custom customApp = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");

      if(null != customApp && null != customApp.get("IncludeReenableApplications")){
        listOfAccounts=customApp.get("IncludeReenableApplications");
      }
      Identity identity = context.getObjectByName(Identity.class, identityName);
      Custom custom = context.getObjectByName(Custom.class,"Ascension-Custom-AD-DomainMapping");
      if (custom != null && null != custom.get("DomainOUMapping")) {
        domainMap = custom.get("DomainOUMapping"); 
      }

      if(null != identity){
        domainAD = identity.getAttribute("domain");
        if(Util.isNotNullOrEmpty(domainAD)){     
          domainAD = domainConversion(domainAD);
        }
        locationID = identity.getAttribute("buildingId");
      }

      if(null != identity && Util.isNotNullOrEmpty(identity.getAttribute("ctrexpDt"))){
        adExpDate = getADFormatedDateString(identity.getAttribute("ctrexpDt"));         
      }

      List linksAccount= (List) identity.getLinks();
      if( null != linksAccount){
        Iterator itrlinksAccount = linksAccount.iterator();
        while (itrlinksAccount.hasNext()){

          Link account = (Link) itrlinksAccount.next();

          if(null != account  && null != account.getApplication()){
            appName = account.getApplicationName();
            accountName = account.getNativeIdentity();
            appType = account.getApplication().getType();
            if(!listOfAccounts.contains(appName)){
              continue;
            }

            ProvisioningPlan.AccountRequest acctReqModify = new ProvisioningPlan.AccountRequest();        
            ProvisioningPlan.AccountRequest enableAccReq = new ProvisioningPlan.AccountRequest();

            if(Util.isNotNullOrEmpty(appName) && Util.isNotNullOrEmpty(accountName) && Util.isNotNullOrEmpty(appType) && appType.equalsIgnoreCase("Active Directory - Direct")){
              if(null != matchingADAccounts && matchingADAccounts.contains(accountName)){
                enableAccReq.setApplication(appName);
                enableAccReq.setNativeIdentity(accountName);
                enableAccReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Enable);
                Attributes atts  = new Attributes();
                atts.put("operationName", "Rehire");
                enableAccReq.setArguments(atts);
                accReqs.add(enableAccReq);  
                displayNamesofAD.add(appName + ":" + account.getDisplayName().toUpperCase());

                if(appName.equalsIgnoreCase("AD-PRESENCEHEALTH")){
                  domainValue = "PRESENCEHEALTH";
                } else{
                  domainValue = domainAD;
                }

                if(null != domainMap && !domainMap.isEmpty() && null != domainMap.get(domainValue)){
                  activeOUMap = domainMap.get(domainValue).get("activeOU");
                  if(null != activeOUMap && !activeOUMap.isEmpty()){ 
                    if(Util.isNotNullOrEmpty(locationID) && Util.isNotNullOrEmpty(activeOUMap.get(locationID))){
                      activeOU = activeOUMap.get(locationID);
                    }
                    else{
                      activeOU = activeOUMap.get("DEFAULT");
                    }
                  }
                }

                //checkIfLeaverDatePastLimit method checks if the leaver date is within 7 seven days from the current date and is not in one of the preset dates from the Leave +61 event
                boolean isLeaverDatePastLimit = checkIfLeaverDatePastLimit(identityName);

                if(account.getIiqDisabled() && isLeaverDatePastLimit){
                  debug(logName, "reseting password for AD account: " + accountName);
                  password = resetPassword(appName, identity);
                }

                acctReqModify.setApplication(appName);
                acctReqModify.setNativeIdentity(accountName);
                acctReqModify.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);

                List attreqs = new ArrayList();

                attreqs = addRequestToChangePasswordAtNextLogin(attreqs);

                if (!Util.nullSafeCaseInsensitiveEq(identity.getStringAttribute("domain"),"AMITA")){
                  if (Util.isNotNullOrEmpty(adExpDate)){
                    attreqs.add(new AttributeRequest("accountExpires", ProvisioningPlan.Operation.Set, adExpDate));
                    description = "";
                  } else{
                    String adAccountExpiresDate = account.getAttribute("accountExpires");
                    String newAccountExpiresDate = calculateAccountExpiresDate(identity, adAccountExpiresDate);
                    if(!Util.nullSafeCaseInsensitiveEq(adAccountExpiresDate, newAccountExpiresDate)){
                      attreqs.add(new AttributeRequest("accountExpires", ProvisioningPlan.Operation.Set, newAccountExpiresDate));
                      description = "";
                    }
                  } 

                } else if(Util.nullSafeCaseInsensitiveEq(identity.getStringAttribute("domain"),"AMITA")){
                  attreqs.add(new AttributeRequest("accountExpires", ProvisioningPlan.Operation.Set, "0"));

                  if( Util.isNotNullOrEmpty(identity.getAttribute("title")) && Util.isNotNullOrEmpty(identity.getAttribute("department"))){
                    description = identity.getAttribute("title")+" - "+identity.getAttribute("department");          
                  }
                } 
                attreqs.add(new AttributeRequest("description", ProvisioningPlan.Operation.Set, description));

                if (Util.isNotNullOrEmpty(password)){
                  attreqs.add(new AttributeRequest("password", ProvisioningPlan.Operation.Set, password));
                }

                if (Util.isNotNullOrEmpty(accountName)) 
                {
                  valueCN= accountName.substring(0, accountName.indexOf("OU=")-1);
                }

                if(Util.isNotNullOrEmpty(activeOU)){
                  attreqs.add(new AttributeRequest("AC_NewParent", ProvisioningPlan.Operation.Set, activeOU));
                }
                if(Util.isNotNullOrEmpty(valueCN)){
                  attreqs.add(new AttributeRequest("AC_NewName", ProvisioningPlan.Operation.Set, valueCN));
                }
                acctReqModify.setAttributeRequests(attreqs);
                accReqs.add(acctReqModify);
              }
            } else if (Util.isNotNullOrEmpty(appName) && Util.isNotNullOrEmpty(accountName) && Util.isNotNullOrEmpty(appType) && appType.equalsIgnoreCase("ServiceNow")){
              if(null != matchingServiceNowAccounts && matchingServiceNowAccounts.contains(accountName)){
                enableAccReq.setApplication(appName);
                enableAccReq.setNativeIdentity(accountName);
                enableAccReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Enable);
                accReqs.add(enableAccReq);   
                displayNamesofSNow.add(appName + ":" + account.getDisplayName().toUpperCase());
              }
            } else if (Util.isNotNullOrEmpty(appName) && Util.isNotNullOrEmpty(accountName)){
              enableAccReq.setApplication(appName);
              enableAccReq.setNativeIdentity(accountName);
              enableAccReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Enable);
              accReqs.add(enableAccReq);   
            }               
          }
        }
        if(null != itrlinksAccount){
          Util.flushIterator(itrlinksAccount);
        } 
      }  
    }
    displayNamesOfEnabledAccounts.put("AD Accounts", displayNamesofAD);
    displayNamesOfEnabledAccounts.put("ServiceNow Accounts", displayNamesofSNow);
    outputMap.put("displayNamesOfEnabledAccounts", displayNamesOfEnabledAccounts);
    outputMap.put("accReqs", accReqs);
    outputMap.put("password", password);

    debug(logName, methodName + "End.");
    return outputMap;
  }

  /***************************************************************************************************
    * This method creates request to add/modify roles based on the identity's domain
    * Method returns the Account Request as a list
    * Input: identityName
    * Output : accReqs - List
    ***************************************************************************************************/

  public List assignRole(String identityName){
    String methodName = "assignRole() - " ;
    debug(logName, methodName + "Start...");
    List accReq = new ArrayList();
    List roleNames = new ArrayList();
    Map domainMap = new HashMap();
    String ministryValue = null;
    String domainAD = null;

    Identity identity = context.getObjectByName(Identity.class, identityName);
    Custom custom = context.getObjectByName(Custom.class,"Ascension-Custom-AD-DomainMapping");

    if( null != identity){
      ministryValue = identity.getAttribute("ministry");
      domainAD = identity.getAttribute("domain");
    }

    if (custom != null && null != custom.get("DomainOUMapping")) {
      domainMap = custom.get("DomainOUMapping");   
      if(null != domainMap && !domainMap.isEmpty() && null != domainMap.get(domainAD)){ 
        roleNames = domainMap.get(domainAD).get("RoleName");
      }
      //comment decache //context.decache(custom);
    }                         
    ProvisioningPlan.AccountRequest iiqAcctReq = new ProvisioningPlan.AccountRequest();
    if(null != roleNames && !roleNames.isEmpty()){


      iiqAcctReq.setApplication("IIQ");
      iiqAcctReq.setNativeIdentity(identityName);
      iiqAcctReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify); 

      if(Util.nullSafeCaseInsensitiveEq(ministryValue,"AMITA Health")){
        for (String roleName: roleNames) {

          iiqAcctReq.add(new AttributeRequest("assignedRoles" , ProvisioningPlan.Operation.Add, roleName));

        } 
      } else {
        iiqAcctReq.add(new AttributeRequest("assignedRoles" , ProvisioningPlan.Operation.Add, "GSuite Access"));
      }
    }
    accReq.add(iiqAcctReq);
    debug(logName, methodName + "End.");
    return accReq;
  }

  /***************************************************************************************************
    * This method is to find the Matching AD account to enable
    * Method returns the Account Name of the matching AD Link
    * Input: identityName
    * Output : accountNameAD - String
    ***************************************************************************************************/

  public Map findMatchingAccounts(String identityName, String samName){
    String methodName = "findMatchingAccounts() - " ;
    debug(logName, methodName + "Start...");
    String appName = null;
    String accountName = null;
    String appType = null;

    Map matchingAccountNames = new HashMap();
    List listOfDomainAccounts = new ArrayList();

    List accountsAD = new ArrayList();
    List accountsServiceNow = new ArrayList();
    Identity identity = context.getObjectByName(Identity.class, identityName);


    if(identity != null){
      String domainAD = null;
      boolean userNameChangeNeeded = checkIfUserNameNeedsToBeChanged(identityName);

      if(userNameChangeNeeded){
        samName = identityName;    
      }  

      //get the domain of the identity
      domainAD = identity.getAttribute("domain");  
      Custom custom = context.getObjectByName(Custom.class, CUSTOM_OBJECT_NAME_REHIRE_CONFIGURATION);

      if(Util.isNotNullOrEmpty(domainAD)){     
        domainAD = domainConversion(domainAD);
        listOfDomainAccounts = custom.get("ADDomainMapping").get(domainAD);
      }

      List linksAccount= (List) identity.getLinks();  
      if( null != linksAccount){
        Iterator itrlinksAccount = linksAccount.iterator();
        while (itrlinksAccount.hasNext()){

          Link account = (Link) itrlinksAccount.next();

          if(null != account  && null != account.getApplication()){
            appName = account.getApplicationName();
            accountName = account.getNativeIdentity();
            appType = account.getApplication().getType();

            if(Util.isNotNullOrEmpty(appName) && Util.isNotNullOrEmpty(accountName) && Util.isNotNullOrEmpty(appType)){
              if(appType.equalsIgnoreCase("Active Directory - Direct") || appType.equalsIgnoreCase("ServiceNow")){
                //get the domain of the account
                String domainofAcc = "";
                String samNameofAcc = "";
                if(appType.equalsIgnoreCase("Active Directory - Direct")){
                  samNameofAcc = account.getAttribute("sAMAccountName");
                  String principalName = account.getAttribute("msDS-PrincipalName");
                  if(Util.isNotNullOrEmpty(principalName)){
                    domainofAcc = getDomain(principalName);
                  }
                  //check if samAccountName and the domainName of the account matches to the identity
                  if(Util.nullSafeCaseInsensitiveEq(samName,samNameofAcc) && (Util.nullSafeCaseInsensitiveEq(domainofAcc,domainAD) || (null != listOfDomainAccounts && listOfDomainAccounts.contains(domainofAcc)))){
                    accountsAD.add(accountName);
                  }
                } else if(appType.equalsIgnoreCase("ServiceNow")){
                  String userName = account.getAttribute("user_name");
                  if(Util.isNotNullOrEmpty(userName)){
                    domainofAcc = getDomain(userName);
                    samNameofAcc = getSamAccountNameFromPrincipalName(userName);
                  }
                  //check if samAccountName and the domainName of the account matches to the identity
                  if(Util.nullSafeCaseInsensitiveEq(samName,samNameofAcc) && (Util.nullSafeCaseInsensitiveEq(domainofAcc,domainAD))){
                    accountsServiceNow.add(accountName);
                  }
                }

                matchingAccountNames.put("AD accounts", accountsAD);
                matchingAccountNames.put("ServiceNow accounts", accountsServiceNow);
              }
            } 
          }
        }

        if(null != itrlinksAccount){
          Util.flushIterator(itrlinksAccount);
        } 

      } 
    }
    debug(logName, methodName + "End.");
    return matchingAccountNames;
  }

  /***************************************************************************************************
    * This method is to get the peopleSoft SET ID Locations from the ministry domain mapping custom object
    * Method returns the peopleSoftSETIDLocations 
    * Input: void
    * Output : peopleSoftSETIDLocations - list
    ***************************************************************************************************/

  public List getPeopleSoftSETIDLocations(){

    String methodName = "getPeopleSoftSETIDLocations() - " ;

    debug(logName, methodName + "Start...");

    List peopleSoftSETIDLocations = new ArrayList() ; 

    if(companyMinistryADDomainMappingCustomObj==null){
      companyMinistryADDomainMappingCustomObj = context.getObjectByName(Custom.class, CUSTOM_OBJECT_NAME_COMPANY_MINISTRY_AD_DOMAIN_MAPPING);
    }

    if(companyMinistryADDomainMappingCustomObj!=null){

      Attributes customObjAttributes = companyMinistryADDomainMappingCustomObj.getAttributes() ;

      List customObjAttributesKeys = customObjAttributes.getKeys() ; 

      if(customObjAttributesKeys!=null && customObjAttributesKeys.size()>0){

        peopleSoftSETIDLocations = customObjAttributesKeys ;     

      } else {

        error(logName, methodName + "Custom object - " + CUSTOM_OBJECT_NAME_COMPANY_MINISTRY_AD_DOMAIN_MAPPING + " - Configuration error.") ;
      }
    } else {

      error(logName, methodName + "Custom object - " + CUSTOM_OBJECT_NAME_COMPANY_MINISTRY_AD_DOMAIN_MAPPING + " - is missing.") ;
    }

    debug(logName, methodName + "End.");
    return peopleSoftSETIDLocations ; 

  }

  /****************************************************************************************************************************
    * This method checks if the given peoplesoft Set ID Location is configured in the ministry domain mapping custom object
    * Method returns if the given SET ID Locations is valid  
    * Input: inPSSoftSETIDLocation
    * Output : validPSSetIDLocation - boolean
    ****************************************************************************************************************************/

  public boolean isValidPSSetIDLocation(String inPSSoftSETIDLocation){

    String methodName = "isValidPSSetIDLocation() - " ;

    debug(logName, methodName + "Start...") ;

    boolean validPSSetIDLocation = false ;

    List peopleSoftSETIDLocations = getPeopleSoftSETIDLocations() ;

    if(peopleSoftSETIDLocations!=null && !Util.isEmpty(peopleSoftSETIDLocations)){

      if(peopleSoftSETIDLocations.contains(inPSSoftSETIDLocation)){

        validPSSetIDLocation = true ; 
      }


    } else {

      error(logName, methodName + "PS SETID Locations configuration is not correct") ;
    }

    debug(logName, methodName + "End.");

    return validPSSetIDLocation ;
  }

  /*********************************************************************************************************
    * This method gets the net bios names for the given company and ministry from the custom object
    * Method returns the net bios names for the given company and ministry 
    * Input: company, ministry
    * Output : netBiosNames - list
    **********************************************************************************************************/

  public List getCompanyNetBiosNames(String company, String ministry){

    String methodName = "getCompanyNetBiosNames() - " ;

    debug(logName, methodName + "Start...");

    List netBiosNames = new ArrayList() ; 

    if(companyNetBiosNamesMappingCustomObj==null){
      companyNetBiosNamesMappingCustomObj = context.getObjectByName(Custom.class, CUSTOM_OBJECT_NAME_COMPANY_NETBIOSNAMES_MAPPING);
    }

    if(companyNetBiosNamesMappingCustomObj!=null){

      Map ministryNetBiosNamesMap = (Map)companyNetBiosNamesMappingCustomObj.get(company) ;

      if(ministryNetBiosNamesMap!=null && !Util.isEmpty(ministryNetBiosNamesMap)){

        Map netBiosNamesMap = ministryNetBiosNamesMap.get(ministry) ;

        if(netBiosNamesMap!=null && !Util.isEmpty(netBiosNamesMap)){

