          }

        } else {

          error(logName, methodName + "ministry - "+ ministry + " - Not configured.") ;

        }

      } else {

        error(logName, methodName + "NetBios Names for company - configuration is not correct") ;

      }

    } else {

      error(logName, methodName + "Custom object - " + CUSTOM_OBJECT_NAME_COMPANY_NETBIOSNAMES_MAPPING + " - is missing.") ;
    }

    debug(logName, methodName + "End.");

    return netBiosNames ;
  }

  /*********************************************************************************************************
    * This method gets the AD Domains for the given SET ID Location and company from the custom object
    * Method returns the AD Domains for the given SET ID Location and company 
    * Input: psSoftSETIDLocation, company
    * Output : adDomains - list
    **********************************************************************************************************/

  public List getADDomains(String psSoftSETIDLocation, String company){

    String methodName = "getADDomains() - " ;

    debug(logName, methodName + "Start...");

    List adDomains = new ArrayList() ; 

    if(isValidPSSetIDLocation(psSoftSETIDLocation)){

      if(companyMinistryADDomainMappingCustomObj==null){
        companyMinistryADDomainMappingCustomObj = context.getObjectByName(Custom.class, CUSTOM_OBJECT_NAME_COMPANY_MINISTRY_AD_DOMAIN_MAPPING);
      }

      if(companyMinistryADDomainMappingCustomObj!=null){

        Map psSoftSETIDLocationMap = (Map)companyMinistryADDomainMappingCustomObj.get(psSoftSETIDLocation) ;

        if(psSoftSETIDLocationMap!=null && !Util.isEmpty(psSoftSETIDLocationMap)){

          Map companyMap = psSoftSETIDLocationMap.get(company) ;

          if(companyMap!=null && !Util.isEmpty(companyMap)){

            List adDomainsList = (List)companyMap.get("AD Domain") ; 

            if(adDomainsList!=null && !Util.isEmpty(adDomainsList)){

              adDomains = adDomainsList ;

            } else {

              error(logName, methodName + "AD Domains Not configured.") ;

            }

          } else {

            error(logName, methodName + "Company - "+ company + " - Not configured.") ;

          }

        } else {

          error(logName, methodName + "PS SETID Locations configuration is not correct") ;

        }

      } else {

        error(logName, methodName + "Custom object - " + CUSTOM_OBJECT_NAME_COMPANY_MINISTRY_AD_DOMAIN_MAPPING + " - is missing.") ;
      }

    } else {

      error(logName, methodName + psSoftSETIDLocation + " is not a valid PeopleSoft SETID Location.") ;
    }

    debug(logName, methodName + "End.");



    return adDomains ;
  }

  /*********************************************************************************************************
    * This method constructs the potential AD account names using the valid AD domains and network logon id
    * Method returns the list of potential accounts for rehire 
    * Input: psSoftSETIDLocation, company, networkLogonID
    * Output : potentialADAccountsList - list
    **********************************************************************************************************/

  public List getPotentialADAccountsForPSSETIDLocationNCompany(String psSoftSETIDLocation, String company, String networkLogonID){

    String methodName = "getPotentialADAccountsForPSSETIDLocationNCompany() - " ;

    debug(logName, methodName + "Start...");  

    List potentialADAccountsList = new ArrayList() ;

    List adDomains = getADDomains(psSoftSETIDLocation, company) ;

    if(adDomains!=null && !Util.isEmpty(adDomains)){

      for(String adDomain: adDomains){

        String[] adDomainsStrArray = adDomain.split(DOT) ;

        potentialADAccountsList.add(adDomainsStrArray[0]+"\\"+networkLogonID.toUpperCase()) ;
      }

    } else {

      error(logName, methodName + "No AD Domains found") ;

    }

    debug(logName, methodName + "End.");

    return potentialADAccountsList ;

  }

