  /*********************************************************************************************************
    * This method is to find the Set ID Location for the given identity
    * Method returns the Set ID Location
    * Input: idService, identityObj
    * Output : psSoftSETIDLocation - string
    **********************************************************************************************************/

  public String getSETIDLocationForUser(IdentityService idService, Identity identityObj){

    String methodName = "getSETIDLocationForUser() - " ;

    debug(logName, methodName + "Start...");

    String psSoftSETIDLocation = null ;

    Application dbPeopleSoftApplObj = context.getObjectByName(Application.class, APP_NAME_DB_PEOPLESOFT);

    List dbPeopleSoftLinks = idService.getLinks(identityObj,dbPeopleSoftApplObj) ;

    if(dbPeopleSoftLinks!=null && !Util.isEmpty(dbPeopleSoftLinks) && (dbPeopleSoftLinks.size()==1)){ 

      Link dbPeopleSoftAccountLink =  dbPeopleSoftLinks.get(0) ;

      psSoftSETIDLocation = (dbPeopleSoftAccountLink.getAttribute("SETID_LOCATION")!=null) ? (String)dbPeopleSoftAccountLink.getAttribute("SETID_LOCATION") : null ;


    } else {

      error(logName, methodName + "Error - PeopleSoft Account not available or more than 1 account exist.") ;

    }  

    debug(logName, methodName + "End.");

    return psSoftSETIDLocation ;
  }

  /*********************************************************************************************************
    * This method is to find the potential accounts for rehire for the given identity
    * Method returns the potential accounts for the given identity
    * Input: inIdentityCubeName, inPSSoftSETIDLocation
    * Output : outputMap - Map
    **********************************************************************************************************/

  public Map findPotentialAccountsForRehire(String inIdentityCubeName, String inPSSoftSETIDLocation){

    String methodName = "findPotentialAccountsForRehire() - " ;

    debug(logName, methodName + "Start...");


    String identityName = "" ;
    String company = "" ;
    String networkLogonID = "" ;
    String psSoftSETIDLocation = "" ;
    String ministry = "" ;

    boolean identityInactive = false ;

    List filteredIdentityAccountLinks = null ;

    List potentialAccountsList = null ; 

    Map outputMap = new HashMap() ;

    if(Util.isNotNullOrEmpty(inIdentityCubeName)){

      // Get Identity Attributes and Links

      Identity identityObj = context.getObjectByName(Identity.class, inIdentityCubeName);

      if(identityObj!=null){

        IdentityService idService = new IdentityService(context) ;

        identityName = identityObj.getName() ;
        identityInactive = identityObj.isInactive() ;
        company = identityObj.getAttribute("company") ;
        networkLogonID = identityObj.getAttribute("samAccountName") ;
        ministry = identityObj.getAttribute("ministry") ;

        if(Util.isNotNullOrEmpty(inPSSoftSETIDLocation)){

          psSoftSETIDLocation = inPSSoftSETIDLocation ; 

        } else {
          psSoftSETIDLocation = getSETIDLocationForUser(idService,identityObj) ;
        }

        if(Util.isNotNullOrEmpty(psSoftSETIDLocation) && Util.isNotNullOrEmpty(company) && Util.isNotNullOrEmpty(networkLogonID)){

          List potentialADAccountsList = getPotentialADAccountsForPSSETIDLocationNCompany(psSoftSETIDLocation, company, networkLogonID) ;

          if(includeReenableApplicationsList==null){

            includeReenableApplicationsList = getIncludeReenableApplicationsList() ;
          }

          List identityAccountLinks = identityObj.getLinks() ;

          filteredIdentityAccountLinks = new ArrayList() ;

          if(identityAccountLinks!=null && !Util.isEmpty(identityAccountLinks)){

            for(Link identityAccountLink: identityAccountLinks){

              if(includeReenableApplicationsList.contains(identityAccountLink.getApplicationName())){

                filteredIdentityAccountLinks.add(identityAccountLink) ;
              }
            }

          } else {

            error(logName, methodName + "No Accounts present on the identity.") ;
          }


          potentialAccountsList = new ArrayList() ;

          if(filteredIdentityAccountLinks!=null && !Util.isEmpty(filteredIdentityAccountLinks)){

            for(Link identityAccountLink: filteredIdentityAccountLinks){

              if(Util.isNotNullOrEmpty(identityAccountLink.getDisplayName()) && potentialADAccountsList.contains(identityAccountLink.getDisplayName().toUpperCase())){

                potentialAccountsList.add(identityAccountLink.getApplicationName() + ":" +identityAccountLink.getNativeIdentity()) ;

              } 
            }


            // If Potential Accounts List is not found with above logic then compare it against NetBiosNames
            if(Util.isEmpty(potentialAccountsList) && Util.isNotNullOrEmpty(ministry)){

              List potentialADAccountsOnNetBiosNamesList = getPotentialADAccountsOnNetBiosNames(company, ministry, networkLogonID) ;

              for(Link identityAccountLink: filteredIdentityAccountLinks){

                if(Util.isNotNullOrEmpty(identityAccountLink.getDisplayName()) && potentialADAccountsOnNetBiosNamesList.contains(identityAccountLink.getDisplayName().toUpperCase())){

                  potentialAccountsList.add(identityAccountLink.getApplicationName() + ":" +identityAccountLink.getNativeIdentity()) ;
                }
              }

            }

            // Remove duplicates
            Util.removeDuplicates(potentialAccountsList) ;

            if(Util.isEmpty(potentialAccountsList)){

              info(logName, methodName + "No Accounts found for Rehire.") ;

            }           

          } else {

            error(logName, methodName + "No Accounts found after filtering against Reenable Application List.") ;
          }

        }


        outputMap.put("identityName",identityName) ;
        outputMap.put("identityInactive",identityInactive) ;
        outputMap.put("company",company) ;
        outputMap.put("networkLogonID",networkLogonID) ;
        outputMap.put("psSoftSETIDLocation",psSoftSETIDLocation) ;
        outputMap.put("networkLogonID",networkLogonID) ;
        outputMap.put("filteredIdentityAccountLinks",filteredIdentityAccountLinks) ;
        outputMap.put("potentialAccountsList",potentialAccountsList) ;


      } else {

        error(logName, methodName + "Identity not found.") ;

      }

    } else {

      error(logName, methodName + "Input Identity Cube Name is empty / null") ;

    }

    debug(logName, methodName + "End.");
    return outputMap ;
  }

