  /***************************************************************************************************
    * This method is to get all the attributes needed for validations needed for rehire trigger after immediate termination
    * Method returns the attributes map
    * Input: identity
    * Output : attributesMap
    ***************************************************************************************************/


  public Map getAttributeMap(Identity identity){
    String methodName = "getAttributeMap() - " ;
    debug(logName, methodName + "Start...");
    Map attributesMap = new HashMap();
    boolean linkStatus = false;
    String hrAppAccount =null;
    String action = null;
    List identityLinks = identity.getLinks();
    for(Link link:identityLinks){
      if(APP_NAME_DB_PEOPLESOFT.equalsIgnoreCase(link.getApplicationName())){
        linkStatus=link.getIiqDisabled();
       
        hrAppAccount=APP_NAME_DB_PEOPLESOFT;
        action = link.getAttribute("ACTION");
       
        attributesMap.put("linkStatus",linkStatus);
        attributesMap.put("hrAppAccount",hrAppAccount);
        attributesMap.put("action",action);
        break;
      }
      else if(APP_NAME_MD_STAFF_AMITA.equalsIgnoreCase(link.getApplicationName())){
        linkStatus=link.getIiqDisabled();
       
        hrAppAccount=MDStaff_AMITA;
        attributesMap.put("linkStatus",linkStatus);
        attributesMap.put("hrAppAccount",hrAppAccount);
        break;
      }
    }
    debug(logName, methodName + "End.");
    return attributesMap;
  }
